31. /// human-readable strings with configurable precision, culture, and unit ranges.
32. /// </summary>
33. public static class TimeSpanReadabilityExtensions
34. {
35.     private const int DaysInAWeek = 7;
36.     private const double DaysInAYear = 365.2425;
37.     private const double DaysInAMonth = DaysInAYear / 12;
38. 
39.     // Anti-pattern: Enumerable.Reverse at static init — allocates an intermediate array
40.     // Could be replaced with a reversed array literal: [TimeUnit.Millisecond, ..., TimeUnit.Year]
41.     private static readonly TimeUnit[] TimeUnits = [.. Enumerable.Reverse(Enum.GetValues<TimeUnit>())];
42. 
43.     /// <summary>
44.     /// Converts a <see cref="TimeSpan"/> to a human-readable string.
45.     /// </summary>
46.     /// <param name="timeSpan">The time span to humanize.</param>
47.     /// <param name="precision">The number of time units to include (e.g., 2 for "1 hour, 30 minutes").</param>
48.     /// <param name="culture">The culture for localized formatting. Uses current culture if null.</param>
49.     /// <param name="maxUnit">The largest time unit to display.</param>
50.     /// <param name="minUnit">The smallest time unit to display.</param>
51.     /// <param name="collectionSeparator">The separator between time parts (default: ", ").</param>
52.     /// <param name="countEmptyUnits">Whether empty units count toward precision.</param>
53.     /// <returns>A human-readable string representation of the time span.</returns>
54.     /// <example>
55.     /// <code>
56.     /// TimeSpan.FromMinutes(90).Humanize() => "1 hour"
57.     /// TimeSpan.FromMinutes(90).Humanize(precision: 2) => "1 hour, 30 minutes"
58.     /// TimeSpan.FromDays(1.5).Humanize(precision: 3) => "1 day, 12 hours"
59.     /// </code>
60.     /// </example>
61.     public static string Humanize(
62.         this TimeSpan timeSpan,
63.         int precision = 1,
64.         CultureInfo? culture = null,
65.         TimeUnit maxUnit = TimeUnit.Year,
66.         TimeUnit minUnit = TimeUnit.Millisecond,
67.         string? collectionSeparator = null,
68.         bool countEmptyUnits = false)
69.     {
70.         culture ??= CultureInfo.CurrentCulture;
71. 
72.         var timeParts = CreateTimeParts(timeSpan, maxUnit, minUnit, culture);
73. 
74.         if (IsContainingOnlyNullValue(timeParts))
75.         {
76.             return CreateTimePartsWithNoTimeValue("no time")[0] ?? "no time";
77.         }
78. 
79.         timeParts = SetPrecisionOfTimeSpan(timeParts, precision, countEmptyUnits);
80. 
81.         return ConcatenateTimeSpanParts(timeParts, culture, collectionSeparator ?? ", ");
82.     }
83. 
84.     /// <summary>
85.     /// Breaks down a TimeSpan into its component time part strings for each unit
86.     /// between maxUnit and minUnit.
87.     /// </summary>
88.     private static List<string?> CreateTimeParts(
89.         TimeSpan timeSpan, TimeUnit maxUnit, TimeUnit minUnit, CultureInfo culture)
90.     {
91.         var timeParts = new List<string?>(8);
92.         var totalDays = Math.Abs(timeSpan.TotalDays);
93.         var totalHours = Math.Abs(timeSpan.TotalHours);
94.         var totalMinutes = Math.Abs(timeSpan.TotalMinutes);
95.         var totalSeconds = Math.Abs(timeSpan.TotalSeconds);
96.         var totalMilliseconds = Math.Abs(timeSpan.TotalMilliseconds);
97. 
98.         foreach (var unit in TimeUnits)
99.         {
100.             if (unit < minUnit || unit > maxUnit)
101.             {
102.                 continue;
103.             }
104. 
105.             var value = unit switch
106.             {
107.                 TimeUnit.Year => (int)(totalDays / DaysInAYear),
108.                 TimeUnit.Month => (int)((totalDays % DaysInAYear) / DaysInAMonth),
109.                 TimeUnit.Week => (int)((totalDays % DaysInAMonth) / DaysInAWeek),
110.                 TimeUnit.Day => (int)(totalDays % DaysInAWeek),
111.                 TimeUnit.Hour => timeSpan.Hours,
112.                 TimeUnit.Minute => timeSpan.Minutes,
113.                 TimeUnit.Second => timeSpan.Seconds,
114.                 TimeUnit.Millisecond => timeSpan.Milliseconds,
115.                 _ => 0
116.             };
117. 
118.             timeParts.Add(value != 0 ? FormatTimePart(value, unit, culture) : null);
119.         }
120. 
121.         return timeParts;
122.     }
123. 
124.     private static List<string?> CreateTimePartsWithNoTimeValue(string noTimeValue) =>
125.         [noTimeValue];
126. 
127.     private static bool IsContainingOnlyNullValue(IEnumerable<string?> timeParts) =>
128.         !timeParts.Any(x => x != null);
129. 
130.     /// <summary>
131.     /// Filters and limits time parts to the requested precision.
132.     /// </summary>
133.     private static List<string?> SetPrecisionOfTimeSpan(
134.         IEnumerable<string?> timeParts, int precision, bool countEmptyUnits)
135.     {
136.         // Anti-pattern: chained .Where().Take().Where() — 3 enumerator allocations
137.         // Plus [.. timeParts] collection expression allocates a final list
138.         if (!countEmptyUnits)
139.         {
140.             timeParts = timeParts.Where(x => x != null);
141.         }
142. 
143.         timeParts = timeParts.Take(precision);
144.         if (countEmptyUnits)
145.         {
146.             timeParts = timeParts.Where(x => x != null);
147.         }
148. 
149.         return [.. timeParts];
150.     }
