152.     /// <summary>
153.     /// Joins time part strings with the specified separator.
154.     /// </summary>
155.     private static string ConcatenateTimeSpanParts(
156.         IEnumerable<string?> timeSpanParts, CultureInfo culture, string collectionSeparator)
157.     {
158.         var parts = timeSpanParts.Where(x => x != null).ToList();
159.         if (parts.Count == 0)
160.         {
161.             return "no time";
162.         }
163. 
164.         if (parts.Count == 1)
165.         {
166.             return parts[0]!;
167.         }
168. 
169.         var allButLast = string.Join(collectionSeparator, parts.Take(parts.Count - 1));
170.         return $"{allButLast} and {parts[^1]}";
171.     }
