173.     private static string FormatTimePart(int value, TimeUnit unit, CultureInfo culture)
174.     {
175.         var unitName = unit.ToString().ToLowerInvariant();
176.         return value == 1 ? $"{value} {unitName}" : $"{value} {unitName}s";
177.     }
