    /// <example>
    /// <code>
    /// TimeSpan.FromMinutes(90).Humanize() => "1 hour"
    /// TimeSpan.FromMinutes(90).Humanize(precision: 2) => "1 hour, 30 minutes"
    /// TimeSpan.FromDays(1.5).Humanize(precision: 3) => "1 day, 12 hours"
    /// </code>
    /// </example>
