    /// <summary>
    /// Formats with an object-returning formatter, converting via .ToString().
    /// </summary>
    public string Humanize<T>(
        IEnumerable<T> collection, Func<T, object?> objectFormatter, string separator)
    {
        ArgumentNullException.ThrowIfNull(collection);
        ArgumentNullException.ThrowIfNull(objectFormatter);

        return HumanizeDisplayStrings(
            collection.Select(o => objectFormatter(o)?.ToString()),
            separator);
    }

    private string HumanizeDisplayStrings(IEnumerable<string?> strings, string separator)
    {
        var items = new List<string>();
        foreach (var item in strings)
        {
            if (item == null)
            {
                continue;
            }

            var trimmed = item.AsSpan().Trim();
            if (trimmed.Length > 0)
            {
                items.Add(trimmed.Length == item.Length ? item : trimmed.ToString());
            }
        }

        if (items.Count == 0)
        {
            return string.Empty;
        }

        if (items.Count == 1)
        {
            return items[0];
        }

#if NET8_0_OR_GREATER
        var allButLast = string.Join(separator,
            System.Runtime.InteropServices.CollectionsMarshal.AsSpan(items)[..^1]);
#else
        var allButLast = string.Join(separator, items.Take(items.Count - 1));
#endif
        return $"{allButLast} and {items[^1]}";
    }
}

