5. /// <summary>
6. /// Specifies the unit of time for humanization purposes.
7. /// Values are ordered from largest to smallest.
8. /// </summary>
9. public enum TimeUnit
10. {
11.     /// <summary>Years.</summary>
12.     Year,
13.     /// <summary>Months.</summary>
14.     Month,
15.     /// <summary>Weeks.</summary>
16.     Week,
17.     /// <summary>Days.</summary>
18.     Day,
19.     /// <summary>Hours.</summary>
20.     Hour,
21.     /// <summary>Minutes.</summary>
22.     Minute,
23.     /// <summary>Seconds.</summary>
24.     Second,
25.     /// <summary>Milliseconds.</summary>
26.     Millisecond
27. }
28. 
29. /// <summary>
30. /// Provides extension methods for converting <see cref="TimeSpan"/> values to
31. /// human-readable strings with configurable precision, culture, and unit ranges.
32. /// </summary>
33. public static class TimeSpanReadabilityExtensions
34. {
35.     private const int DaysInAWeek = 7;
36.     private const double DaysInAYear = 365.2425;
37.     private const double DaysInAMonth = DaysInAYear / 12;
38. 
39.     private static readonly TimeUnit[] TimeUnits =
40.     [
41.         TimeUnit.Millisecond, TimeUnit.Second, TimeUnit.Minute, TimeUnit.Hour,
42.         TimeUnit.Day, TimeUnit.Week, TimeUnit.Month, TimeUnit.Year
43.     ];
44. 
45.     // Cached lowercase unit names indexed by TimeUnit ordinal to avoid
46.     // repeated enum.ToString() + ToLowerInvariant() allocations.
47.     private static readonly string[] UnitNamesSingular;
48.     private static readonly string[] UnitNamesPlural;
49. 
50.     static TimeSpanReadabilityExtensions()
51.     {
52.         var values = Enum.GetValues<TimeUnit>();
53.         UnitNamesSingular = new string[values.Length];
54.         UnitNamesPlural = new string[values.Length];
55.         foreach (var unit in values)
56.         {
57.             var name = unit.ToString().ToLowerInvariant();
58.             UnitNamesSingular[(int)unit] = name;
59.             UnitNamesPlural[(int)unit] = name + "s";
60.         }
61.     }
62. 
63.     /// <summary>
64.     /// Converts a <see cref="TimeSpan"/> to a human-readable string.
65.     /// </summary>
66.     /// <param name="timeSpan">The time span to humanize.</param>
67.     /// <param name="precision">The number of time units to include (e.g., 2 for "1 hour, 30 minutes").</param>
68.     /// <param name="culture">The culture for localized formatting. Uses current culture if null.</param>
69.     /// <param name="maxUnit">The largest time unit to display.</param>
70.     /// <param name="minUnit">The smallest time unit to display.</param>
71.     /// <param name="collectionSeparator">The separator between time parts (default: ", ").</param>
72.     /// <param name="countEmptyUnits">Whether empty units count toward precision.</param>
73.     /// <returns>A human-readable string representation of the time span.</returns>
74.     /// <example>
75.     /// <code>
76.     /// TimeSpan.FromMinutes(90).Humanize() => "1 hour"
77.     /// TimeSpan.FromMinutes(90).Humanize(precision: 2) => "1 hour, 30 minutes"
78.     /// TimeSpan.FromDays(1.5).Humanize(precision: 3) => "1 day, 12 hours"
79.     /// </code>
80.     /// </example>
81.     public static string Humanize(
82.         this TimeSpan timeSpan,
83.         int precision = 1,
84.         CultureInfo? culture = null,
85.         TimeUnit maxUnit = TimeUnit.Year,
86.         TimeUnit minUnit = TimeUnit.Millisecond,
87.         string? collectionSeparator = null,
88.         bool countEmptyUnits = false)
89.     {
90.         culture ??= CultureInfo.CurrentCulture;
91. 
92.         var timeParts = CreateTimeParts(timeSpan, maxUnit, minUnit, culture);
93. 
94.         if (IsContainingOnlyNullValue(timeParts))
95.         {
96.             return "no time";
97.         }
98. 
99.         timeParts = SetPrecisionOfTimeSpan(timeParts, precision, countEmptyUnits);
100. 
101.         return ConcatenateTimeSpanParts(timeParts, collectionSeparator ?? ", ");
102.     }
103. 
104.     /// <summary>
105.     /// Breaks down a TimeSpan into its component time part strings for each unit
106.     /// between maxUnit and minUnit.
107.     /// </summary>
108.     private static List<string?> CreateTimeParts(
109.         TimeSpan timeSpan, TimeUnit maxUnit, TimeUnit minUnit, CultureInfo culture)
110.     {
111.         var timeParts = new List<string?>(8);
112.         var totalDays = Math.Abs(timeSpan.TotalDays);
113. 
114.         foreach (var unit in TimeUnits)
115.         {
116.             if (unit < minUnit || unit > maxUnit)
117.             {
118.                 continue;
119.             }
120. 
121.             var value = unit switch
122.             {
123.                 TimeUnit.Year => (int)(totalDays / DaysInAYear),
124.                 TimeUnit.Month => (int)((totalDays % DaysInAYear) / DaysInAMonth),
125.                 TimeUnit.Week => (int)((totalDays % DaysInAMonth) / DaysInAWeek),
126.                 TimeUnit.Day => (int)(totalDays % DaysInAWeek),
127.                 TimeUnit.Hour => timeSpan.Hours,
128.                 TimeUnit.Minute => timeSpan.Minutes,
129.                 TimeUnit.Second => timeSpan.Seconds,
130.                 TimeUnit.Millisecond => timeSpan.Milliseconds,
131.                 _ => 0
132.             };
133. 
134.             timeParts.Add(value != 0 ? FormatTimePart(value, unit) : null);
135.         }
136. 
137.         return timeParts;
138.     }
139. 
140.     private static bool IsContainingOnlyNullValue(List<string?> timeParts)
141.     {
142.         for (var i = 0; i < timeParts.Count; i++)
143.         {
144.             if (timeParts[i] != null)
145.             {
146.                 return false;
147.             }
148.         }
149. 
150.         return true;
151.     }
152. 
153.     /// <summary>
154.     /// Filters and limits time parts to the requested precision.
155.     /// </summary>
156.     private static List<string?> SetPrecisionOfTimeSpan(
157.         List<string?> timeParts, int precision, bool countEmptyUnits)
158.     {
159.         var result = new List<string?>(precision);
160.         var taken = 0;
161. 
162.         for (var i = 0; i < timeParts.Count && taken < precision; i++)
163.         {
164.             var part = timeParts[i];
165.             if (countEmptyUnits)
166.             {
167.                 taken++;
168.                 if (part != null)
169.                 {
170.                     result.Add(part);
171.                 }
172.             }
173.             else if (part != null)
174.             {
175.                 result.Add(part);
176.                 taken++;
177.             }
178.         }
179. 
180.         return result;
181.     }
182. 
183.     /// <summary>
184.     /// Joins time part strings with the specified separator.
185.     /// </summary>
186.     private static string ConcatenateTimeSpanParts(
187.         List<string?> timeSpanParts, string collectionSeparator)
188.     {
189.         // timeSpanParts from SetPrecisionOfTimeSpan already contains only non-null entries,
190.         // but guard against nulls defensively.
191.         var count = timeSpanParts.Count;
192.         if (count == 0)
193.         {
194.             return "no time";
195.         }
196. 
197.         if (count == 1)
198.         {
199.             return timeSpanParts[0]!;
200.         }
201. 
202. #if NET8_0_OR_GREATER
203.         var allButLast = string.Join(collectionSeparator,
204.             System.Runtime.InteropServices.CollectionsMarshal.AsSpan(timeSpanParts)[..^1]);
205. #else
206.         var allButLast = string.Join(collectionSeparator, timeSpanParts.Take(count - 1));
207. #endif
208.         return $"{allButLast} and {timeSpanParts[^1]}";
209.     }
210. 
211.     private static string FormatTimePart(int value, TimeUnit unit)
212.     {
213.         var unitName = value == 1
214.             ? UnitNamesSingular[(int)unit]
215.             : UnitNamesPlural[(int)unit];
216.         return $"{value} {unitName}";
217.     }
218. }
