220. /// <summary>
221. /// Defines the contract for formatting a collection of items into a human-readable string.
222. /// </summary>
223. public interface ICollectionFormatter
224. {
225.     /// <summary>
226.     /// Formats a collection into a human-readable string using the default separator.
227.     /// </summary>
228.     /// <typeparam name="T">The type of items in the collection.</typeparam>
229.     /// <param name="collection">The collection to format.</param>
230.     /// <returns>A human-readable string representation of the collection.</returns>
231.     string Humanize<T>(IEnumerable<T> collection);
232. 
233.     /// <summary>
234.     /// Formats a collection using a custom object formatter and default separator.
235.     /// </summary>
236.     string Humanize<T>(IEnumerable<T> collection, Func<T, string?> objectFormatter);
237. 
238.     /// <summary>
239.     /// Formats a collection using a custom separator.
