256.     public virtual string Humanize<T>(IEnumerable<T> collection) =>
257.         Humanize(collection, o => o?.ToString(), DefaultSeparator);
258. 
259.     /// <inheritdoc />
260.     public virtual string Humanize<T>(IEnumerable<T> collection, Func<T, string?> objectFormatter) =>
261.         Humanize(collection, objectFormatter, DefaultSeparator);
262. 
263.     /// <summary>
264.     /// Formats a collection using an object-returning formatter.
265.     /// </summary>
266.     public string Humanize<T>(IEnumerable<T> collection, Func<T, object?> objectFormatter) =>
267.         Humanize(collection, objectFormatter, DefaultSeparator);
268. 
269.     /// <inheritdoc />
270.     public virtual string Humanize<T>(IEnumerable<T> collection, string separator) =>
271.         Humanize(collection, o => o?.ToString(), separator);
272. 
273.     /// <summary>
274.     /// Core formatting method that converts a collection to a human-readable string.
275.     /// </summary>
276.     public virtual string Humanize<T>(
277.         IEnumerable<T> collection, Func<T, string?> objectFormatter, string separator)
278.     {
279.         ArgumentNullException.ThrowIfNull(collection);
