301.     private string HumanizeDisplayStrings(IEnumerable<string?> strings, string separator)
302.     {
303.         var items = new List<string>();
304.         foreach (var item in strings)
305.         {
306.             if (item == null)
307.             {
308.                 continue;
309.             }
310. 
311.             var trimmed = item.AsSpan().Trim();
312.             if (trimmed.Length > 0)
313.             {
314.                 items.Add(trimmed.Length == item.Length ? item : trimmed.ToString());
315.             }
316.         }
